   184	               uint16_t RBstart,
   185	               uint16_t Lcrbs)
   186	//------------------------------------------------------------------------------
   187	{
   188	  if (Lcrbs <= (1 + (N_RB_DL >> 1))) {
   189	    return (N_RB_DL * (Lcrbs - 1)) + RBstart;
   190	  }
   191	
   192	  return (N_RB_DL * (N_RB_DL + 1 - Lcrbs)) + (N_RB_DL - 1 - RBstart);
